import{_ as a,o as e,c as s,ae as i}from"./chunks/framework.C7FLYIpo.js";const m=JSON.parse('{"title":"내장 메모리 엔진","description":"키워드, 벡터, 하이브리드 검색이 있는 기본 SQLite 기반 메모리 백엔드","frontmatter":{"title":"내장 메모리 엔진","description":"키워드, 벡터, 하이브리드 검색이 있는 기본 SQLite 기반 메모리 백엔드"},"headers":[],"relativePath":"concepts/memory-builtin.md","filePath":"concepts/memory-builtin.md","lastUpdated":null}'),o={name:"concepts/memory-builtin.md"};function n(l,t,d,r,p,c){return e(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="내장-메모리-엔진" tabindex="-1">내장 메모리 엔진 <a class="header-anchor" href="#내장-메모리-엔진" aria-label="Permalink to &quot;내장 메모리 엔진&quot;">​</a></h1><p>내장 엔진은 기본 메모리 백엔드입니다. 에이전트별 SQLite 데이터베이스에 메모리 인덱스를 저장하며 시작하기 위한 추가 종속성이 필요하지 않습니다.</p><h2 id="제공하는-것" tabindex="-1">제공하는 것 <a class="header-anchor" href="#제공하는-것" aria-label="Permalink to &quot;제공하는 것&quot;">​</a></h2><ul><li>FTS5 전문 인덱싱 (BM25 점수)을 통한 <strong>키워드 검색</strong>.</li><li>지원되는 프로바이더의 임베딩을 통한 <strong>벡터 검색</strong>.</li><li>최상의 결과를 위해 둘 다 결합하는 <strong>하이브리드 검색</strong>.</li><li>중국어, 일본어, 한국어용 트라이그램 토크나이저를 통한 <strong>CJK 지원</strong>.</li><li>인데이터베이스 벡터 쿼리를 위한 <strong>sqlite-vec 가속</strong> (선택적).</li></ul><h2 id="시작하기" tabindex="-1">시작하기 <a class="header-anchor" href="#시작하기" aria-label="Permalink to &quot;시작하기&quot;">​</a></h2><p>OpenAI, Gemini, Voyage, 또는 Mistral의 API 키가 있다면 내장 엔진이 자동으로 감지하고 벡터 검색을 활성화합니다. 구성이 필요하지 않습니다.</p><p>프로바이더를 명시적으로 설정하려면:</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      memorySearch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        provider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;openai&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>임베딩 프로바이더 없이는 키워드 검색만 사용 가능합니다.</p><h2 id="지원되는-임베딩-프로바이더" tabindex="-1">지원되는 임베딩 프로바이더 <a class="header-anchor" href="#지원되는-임베딩-프로바이더" aria-label="Permalink to &quot;지원되는 임베딩 프로바이더&quot;">​</a></h2><table tabindex="0"><thead><tr><th>프로바이더</th><th>ID</th><th>자동 감지</th><th>참고</th></tr></thead><tbody><tr><td>OpenAI</td><td><code>openai</code></td><td>예</td><td>기본값: <code>text-embedding-3-small</code></td></tr><tr><td>Gemini</td><td><code>gemini</code></td><td>예</td><td>멀티모달 지원 (이미지 + 오디오)</td></tr><tr><td>Voyage</td><td><code>voyage</code></td><td>예</td><td></td></tr><tr><td>Mistral</td><td><code>mistral</code></td><td>예</td><td></td></tr><tr><td>Ollama</td><td><code>ollama</code></td><td>아니오</td><td>로컬, 명시적으로 설정</td></tr><tr><td>Local</td><td><code>local</code></td><td>예 (첫 번째)</td><td>GGUF 모델, ~0.6 GB 다운로드</td></tr></tbody></table><p>자동 감지는 API 키를 확인할 수 있는 첫 번째 프로바이더를 표시된 순서로 선택합니다. 오버라이드하려면 <code>memorySearch.provider</code>를 설정하십시오.</p><h2 id="인덱싱-작동-방식" tabindex="-1">인덱싱 작동 방식 <a class="header-anchor" href="#인덱싱-작동-방식" aria-label="Permalink to &quot;인덱싱 작동 방식&quot;">​</a></h2><p>OpenClaw는 <code>MEMORY.md</code> 및 <code>memory/*.md</code>를 청크 (~400 토큰, 80 토큰 오버랩)로 인덱싱하고 에이전트별 SQLite 데이터베이스에 저장합니다.</p><ul><li><strong>인덱스 위치:</strong> <code>~/.openclaw/memory/&lt;agentId&gt;.sqlite</code></li><li><strong>파일 감시:</strong> 메모리 파일의 변경사항이 디바운스된 재인덱싱을 트리거합니다 (1.5초).</li><li><strong>자동 재인덱싱:</strong> 임베딩 프로바이더, 모델, 또는 청킹 구성이 변경되면 전체 인덱스가 자동으로 재빌드됩니다.</li><li><strong>요청 시 재인덱싱:</strong> <code>openclaw memory index --force</code></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p><code>memorySearch.extraPaths</code>로 워크스페이스 외부의 마크다운 파일도 인덱싱할 수 있습니다. <a href="/openclaw-docs-ko/reference/memory-config#additional-memory-paths">구성 참조</a>를 참조하십시오.</p></div><h2 id="사용-시기" tabindex="-1">사용 시기 <a class="header-anchor" href="#사용-시기" aria-label="Permalink to &quot;사용 시기&quot;">​</a></h2><p>내장 엔진은 대부분의 사용자에게 적합한 선택입니다:</p><ul><li>추가 종속성 없이 즉시 작동합니다.</li><li>키워드 및 벡터 검색을 잘 처리합니다.</li><li>모든 임베딩 프로바이더를 지원합니다.</li><li>하이브리드 검색이 두 검색 접근 방식의 장점을 결합합니다.</li></ul><p>재순위화, 쿼리 확장, 또는 워크스페이스 외부의 디렉터리를 인덱싱해야 하는 경우 <a href="/openclaw-docs-ko/concepts/memory-qmd">QMD</a>로 전환을 고려하십시오.</p><p>자동 사용자 모델링을 통한 크로스 세션 메모리를 원하면 <a href="/openclaw-docs-ko/concepts/memory-honcho">Honcho</a>를 고려하십시오.</p><h2 id="트러블슈팅" tabindex="-1">트러블슈팅 <a class="header-anchor" href="#트러블슈팅" aria-label="Permalink to &quot;트러블슈팅&quot;">​</a></h2><p><strong>메모리 검색이 비활성화되었습니까?</strong> <code>openclaw memory status</code>를 확인하십시오. 프로바이더가 감지되지 않으면 명시적으로 설정하거나 API 키를 추가하십시오.</p><p><strong>오래된 결과입니까?</strong> 재빌드하려면 <code>openclaw memory index --force</code>를 실행하십시오. 감시자는 드문 경우에 변경사항을 놓칠 수 있습니다.</p><p><strong>sqlite-vec가 로드되지 않습니까?</strong> OpenClaw는 자동으로 인프로세스 코사인 유사도로 폴백합니다. 특정 로드 오류에 대한 로그를 확인하십시오.</p><h2 id="구성" tabindex="-1">구성 <a class="header-anchor" href="#구성" aria-label="Permalink to &quot;구성&quot;">​</a></h2><p>임베딩 프로바이더 설정, 하이브리드 검색 조정 (가중치, MMR, 시간 감쇠), 배치 인덱싱, 멀티모달 메모리, sqlite-vec, 추가 경로, 기타 모든 구성 설정은 <a href="/openclaw-docs-ko/reference/memory-config">메모리 구성 참조</a>를 참조하십시오.</p>`,27)])])}const k=a(o,[["render",n]]);export{m as __pageData,k as default};
